@SuppressWarnings("UnnecessaryReturnStatement")
    @Override
    public void log(Level level, String name, Marker marker, String message, Throwable throwable) {
        if (level == null) {
            level = Level.WARN;
        }
        switch (level) {
            case TRACE:
                Log.v(name, message, throwable);
                return;
            case DEBUG:
                Log.d(name, message, throwable);
                return;
            case INFO:
                Log.i(name, message, throwable);
                return;
            case WARN:
                Log.w(name, message, throwable);
                return;
            case ERROR:
                Log.e(name, message, throwable);
                return;
        }
    }
